#!/usr/bin/env python3 """graph_ir.models — Pydantic models for graph-ai.json IR schema.  四层分离: logic (graph) / view / sourceMap / metadata 节点类型: control / structure / action / data / escape """  from __future__ import annotations  from enum import Enum from typing import Any, Optional  from pydantic import BaseModel, Field   # ── Enums ──   class NodeCategory(str, Enum):     CONTROL = "control"     STRUCTURE = "structure"     ACTION = "action"     DATA = "data"     ESCAPE = "escape"   class PortType(str, Enum):     ANY = "any"     VALUE = "value"     BOOL = "bool"     CALLABLE = "callable"     ITERABLE = "iterable"     TARGET = "target"     BODY = "body"   class GeneratedBy(str, Enum):     PARSER = "parser"     AI = "ai"     MANUAL = "manual"   # ── Port definitions ──   class PortDef(BaseModel):     name: str     type: str = "any"     optional: bool = False   # ── Node ──   class IRNode(BaseModel):     id: str = Field(pattern=r"^node_[a-z0-9_]+$")     category: NodeCategory     type: str     label: str     value: Any = None     inputs: list[PortDef] = Field(default_factory=list)     outputs: list[PortDef] = Field(default_factory=list)     children: list[str] = Field(default_factory=list)     codeBlock: Optional[str] = None   # ── Edge ──   class IREdge(BaseModel):     id: str     source: str     target: str     sourcePort: str = "out"     targetPort: str = "in"     label: str = ""   # ── Scope ──   class IRScope(BaseModel):     id: str     parent: Optional[str] = None     nodes: list[str] = Field(default_factory=list)   # ── Logic layer (graph) ──   class GraphLogic(BaseModel):     nodes: list[IRNode] = Field(default_factory=list)     edges: list[IREdge] = Field(default_factory=list)     variables: dict[str, str] = Field(default_factory=dict)     scopes: list[IRScope] = Field(default_factory=list)   # ── View layer ──   class NodePosition(BaseModel):     x: float = 0.0     y: float = 0.0     collapsed: bool = False     color: Optional[str] = None   class ViewLayer(BaseModel):     nodePositions: dict[str, NodePosition] = Field(default_factory=dict)     theme: str = "default"   # ── SourceMap layer ──   class SourceLocation(BaseModel):     lineStart: int     lineEnd: int     colStart: int = 0     colEnd: int = 0     sourceFile: str = "<source>"   # ── Metadata layer ──   class Metadata(BaseModel):     irVersion: str = "0.1.0"     pythonSubset: str = "mvp-0.1"     generatedAt: str = ""     generatedBy: GeneratedBy = GeneratedBy.PARSER   # ── Full IR document ──   class GraphAIR(BaseModel):     """Top-level graph-ai.json document: logic / view / sourceMap / metadata."""      graph: GraphLogic     view: ViewLayer = Field(default_factory=ViewLayer)     sourceMap: dict[str, SourceLocation] = Field(default_factory=dict)     metadata: Metadata = Field(default_factory=Metadata)      def to_json(self, indent: int = 2) -> str:         return self.model_dump_json(indent=indent)      @classmethod     def from_json(cls, data: str) -> GraphAIR:         return cls.model_validate_json(data)      @classmethod     def from_dict(cls, data: dict) -> GraphAIR:         return cls.model_validate(data)      def node_count(self) -> int:         return len(self.graph.nodes)      def edge_count(self) -> int:         return len(self.graph.edges)      def get_node(self, node_id: str) -> IRNode | None:         for n in self.graph.nodes:             if n.id == node_id:                 return n         return None